import json, re

lines = open('ios_crash.ips').readlines()
raw = ''.join(lines[1:])
raw = re.sub(r'\"vmregioninfo\"', '\"vmregioninfo_lower\"', raw)
crash = json.loads(raw)

# Check for thread names and other useful info
threads = crash.get('threads', [])
for i, t in enumerate(threads):
    name = t.get('name', '')
    queue = t.get('queue', '')
    triggered = t.get('triggered', False)
    extra = []
    if name: extra.append(f'name={name}')
    if queue: extra.append(f'queue={queue}')
    if triggered: extra.append('TRIGGERED')
    print(f'Thread {i}: {\" \".join(extra)} ({len(t.get(\"frames\",[]))} frames)')

# Check termination info
print()
for k in ['termination','lastExceptionBacktrace']:
    if k in crash:
        if k == 'termination':
            print(f'Termination: {crash[k]}')

# Also check the SampleMAUI image UUID for the app binary
images = crash.get('usedImages', [])
for img in images:
    if 'SampleMAUI' in img.get('name',''):
        print(f'SampleMAUI image: uuid={img[\"uuid\"]} base={hex(img[\"base\"])} arch={img[\"arch\"]}')
" 2>&1

